/* == EXEMPLE ===============================================
 * Deadlock avec deux verrous : fork gauche/droite
 * Deux philosophes prennent les fourchettes dans un ordre
 * opposé → deadlock. Solution : même ordre.
 * ========================================================= */
pthread_mutex_t fork_left = PTHREAD_MUTEX_INITIALIZER;
pthread_mutex_t fork_right = PTHREAD_MUTEX_INITIALIZER;

void *philosopher_safe(void *arg) {
    int id = *(int *)arg;
    (void)id;
    /* Toujours left avant right */
    pthread_mutex_lock(&fork_left);
    pthread_mutex_lock(&fork_right);
    /* manger ... */
    pthread_mutex_unlock(&fork_right);
    pthread_mutex_unlock(&fork_left);
    return NULL;
}
